#include <bits/stdc++.h>
using namespace std;
const double eps=1e-6;
int t,n,m,f[1<<18],p[18][18];
//p[i][j]为i和j所组成的抛物线所能覆盖的点的集合
double x[18],y[18];
int cmp(double a,double b){//比较
	if(fabs(a-b)<eps)
		return 0;
	if(a<b)
		return -1;
	return 1;
}
int main(){
    scanf("%d",&t);
    while(t--){
    	memset(p,0,sizeof(p));//初始化
    	scanf("%d%d",&n,&m);
    	for(int i=0;i<n;i++)
    		scanf("%lf%lf",&x[i],&y[i]);
    	for(int i=0;i<n;i++){
    		p[i][i]=1<<i;
    		for(int j=0;j<n;j++){
    			if(!cmp(x[i],x[j]))
    				continue;//相同退出
    			double a=(y[i]/x[i]-y[j]/x[j])/(x[i]-x[j]),b=y[i]/x[i]-a*x[i];
    			if(a>=0)
    				continue;//开口朝上退出
    			for(int k=0;k<n;k++)
    				if(!cmp(a*x[k]*x[k]+b*x[k],y[k]))
    					p[i][j]+=1<<k;
			}
		}
		memset(f,63,sizeof(f));
		f[0]=0;
		for(int i=1;i<1<<n;i++){
			for(int j=0;j<n;j++)
				if((i&(1<<j)))
					for(int k=j;k<n;k++)
						if(i&(1<<k))
							f[i]=min(f[i],f[i-(p[j][k]&i)]+1);
		}
		printf("%d\n",f[(1<<n)-1]);
	}
    return 0;
}
